<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }

  :root {
    --bg-dark: #1e1e2e;
    --bg-darker: #181825;
    --bg-panel: #252536;
    --bg-window: #1e1e2e;
    --bg-header: #313244;
    --accent: #7c6ff7;
    --accent-hover: #9488ff;
    --text: #cdd6f4;
    --text-dim: #a6adc8;
    --text-bright: #f5e0dc;
    --border: #45475a;
    --danger: #f38ba8;
    --success: #a6e3a1;
    --folder-color: #f9e2af;
    --file-color: #cdd6f4;
    --taskbar-h: 48px;
  }

  body {
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    overflow: hidden;
    height: 100vh;
    width: 100vw;
    color: var(--text);
    user-select: none;
  }

  #desktop {
    width: 100vw;
    height: 100vh;
    background: linear-gradient(135deg, #1a1a2e 0%, #16213e 30%, #0f3460 60%, #1a1a2e 100%);
    position: relative;
    overflow: hidden;
  }

  #desktop::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(124,111,247,0.08) 0%, transparent 50%),
      radial-gradient(ellipse at 80% 20%, rgba(249,226,175,0.05) 0%, transparent 40%),
      radial-gradient(ellipse at 50% 80%, rgba(166,227,161,0.04) 0%, transparent 40%);
    pointer-events: none;
  }

  /* ── Taskbar ── */
  #taskbar {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: var(--taskbar-h);
    background: var(--bg-darker);
    border-top: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 0 16px;
    z-index: 1000;
    backdrop-filter: blur(12px);
  }

  .launcher-btn {
    width: 40px;
    height: 40px;
    border-radius: 10px;
    border: none;
    background: var(--bg-panel);
    color: var(--text);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.15s ease;
    position: relative;
  }

  .launcher-btn:hover {
    background: var(--bg-header);
    transform: scale(1.08);
  }

  .launcher-btn:active {
    transform: scale(0.95);
  }

  .launcher-btn.active::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 50%;
    transform: translateX(-50%);
    width: 18px;
    height: 3px;
    border-radius: 2px;
    background: var(--accent);
  }

  .launcher-btn svg {
    width: 22px;
    height: 22px;
    fill: currentColor;
  }

  .launcher-btn .tooltip {
    position: absolute;
    bottom: calc(100% + 8px);
    left: 50%;
    transform: translateX(-50%);
    background: var(--bg-header);
    color: var(--text);
    padding: 4px 10px;
    border-radius: 6px;
    font-size: 12px;
    white-space: nowrap;
    opacity: 0;
    pointer-events: none;
    transition: opacity 0.15s;
    border: 1px solid var(--border);
  }

  .launcher-btn:hover .tooltip {
    opacity: 1;
  }

  /* ── Windows ── */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    background: var(--bg-window);
    border: 1px solid var(--border);
    border-radius: 12px;
    box-shadow: 0 8px 32px rgba(0,0,0,0.45), 0 2px 8px rgba(0,0,0,0.3);
    display: flex;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
    transition: box-shadow 0.2s;
  }

  .window.focused {
    box-shadow: 0 12px 48px rgba(0,0,0,0.55), 0 4px 12px rgba(0,0,0,0.35);
    z-index: 200;
  }

  .window-header {
    height: 38px;
    background: var(--bg-header);
    display: flex;
    align-items: center;
    padding: 0 12px;
    gap: 8px;
    cursor: grab;
    flex-shrink: 0;
    border-bottom: 1px solid var(--border);
  }

  .window-header:active { cursor: grabbing; }

  .window-title {
    flex: 1;
    font-size: 13px;
    font-weight: 600;
    color: var(--text-dim);
    text-align: center;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .win-close {
    width: 28px;
    height: 28px;
    border-radius: 6px;
    border: none;
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.12s;
    flex-shrink: 0;
  }

  .win-close:hover {
    background: var(--danger);
    color: #1e1e2e;
  }

  .window-body {
    flex: 1;
    overflow: auto;
    display: flex;
    flex-direction: column;
  }

  /* ── Files App ── */
  #files-window {
    width: 520px;
    height: 400px;
    top: 60px;
    left: 80px;
  }

  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: var(--bg-panel);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
  }

  #files-up {
    width: 30px;
    height: 30px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: var(--bg-header);
    color: var(--text);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.12s;
    flex-shrink: 0;
  }

  #files-up:hover { background: var(--accent); border-color: var(--accent); }
  #files-up:disabled { opacity: 0.3; cursor: default; }
  #files-up:disabled:hover { background: var(--bg-header); border-color: var(--border); }

  #files-path {
    flex: 1;
    background: var(--bg-darker);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 6px 10px;
    color: var(--text);
    font-size: 13px;
    font-family: 'Cascadia Code', 'Fira Code', monospace;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .files-content {
    flex: 1;
    padding: 8px;
    overflow-y: auto;
  }

  .fs-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 10px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.1s;
    font-size: 13px;
  }

  .fs-item:hover { background: rgba(124,111,247,0.1); }

  .fs-item .icon {
    width: 20px;
    height: 20px;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .fs-item.folder .icon { color: var(--folder-color); }
  .fs-item.file .icon { color: var(--file-color); }

  .fs-item .name {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  /* ── Notepad App ── */
  #notepad-window {
    width: 560px;
    height: 420px;
    top: 90px;
    left: 200px;
  }

  #tabs {
    display: flex;
    align-items: flex-end;
    gap: 2px;
    padding: 6px 8px 0;
    background: var(--bg-panel);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
    overflow-x: auto;
  }

  .tab {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 6px 14px;
    border-radius: 8px 8px 0 0;
    background: var(--bg-header);
    color: var(--text-dim);
    font-size: 12px;
    cursor: pointer;
    border: 1px solid transparent;
    border-bottom: none;
    transition: all 0.1s;
    white-space: nowrap;
    max-width: 140px;
  }

  .tab:hover { background: var(--border); }

  .tab.active {
    background: var(--bg-window);
    color: var(--text);
    border-color: var(--border);
    font-weight: 600;
  }

  .tab .tab-close {
    width: 16px;
    height: 16px;
    border-radius: 4px;
    border: none;
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    line-height: 1;
    transition: all 0.1s;
  }

  .tab .tab-close:hover { background: var(--danger); color: #1e1e2e; }

  #new-tab {
    width: 28px;
    height: 28px;
    border-radius: 6px;
    border: 1px solid var(--border);
    background: var(--bg-header);
    color: var(--text-dim);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    transition: all 0.12s;
    flex-shrink: 0;
    margin-left: 4px;
    margin-bottom: 1px;
  }

  #new-tab:hover { background: var(--accent); color: #fff; border-color: var(--accent); }

  #editor {
    flex: 1;
    width: 100%;
    background: var(--bg-window);
    color: var(--text);
    border: none;
    padding: 12px;
    font-family: 'Cascadia Code', 'Fira Code', 'Consolas', monospace;
    font-size: 14px;
    line-height: 1.6;
    resize: none;
    outline: none;
    tab-size: 4;
  }

  #editor::placeholder { color: var(--text-dim); opacity: 0.5; }

  /* ── Scrollbar ── */
  ::-webkit-scrollbar { width: 6px; height: 6px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
  ::-webkit-scrollbar-thumb:hover { background: var(--text-dim); }

  /* ── Animations ── */
  .window { animation: winOpen 0.2s ease-out; }
  @keyframes winOpen {
    from { opacity: 0; transform: scale(0.95) translateY(8px); }
    to { opacity: 1; transform: scale(1) translateY(0); }
  }

  .window.hiding {
    animation: winClose 0.15s ease-in forwards;
  }
  @keyframes winClose {
    to { opacity: 0; transform: scale(0.97) translateY(4px); }
  }

  /* ── Desktop icons area ── */
  .desktop-icons {
    position: absolute;
    top: 16px;
    left: 16px;
    display: flex;
    flex-direction: column;
    gap: 8px;
    z-index: 1;
  }

  .desktop-icon {
    width: 72px;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    padding: 8px 4px;
    border-radius: 8px;
    cursor: pointer;
    transition: background 0.12s;
  }

  .desktop-icon:hover { background: rgba(255,255,255,0.08); }

  .desktop-icon .di-icon {
    width: 40px;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  .desktop-icon .di-label {
    font-size: 11px;
    color: var(--text);
    text-align: center;
    text-shadow: 0 1px 3px rgba(0,0,0,0.6);
  }

  /* ── Clock ── */
  .taskbar-right {
    position: absolute;
    right: 16px;
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 12px;
    color: var(--text-dim);
  }

  #clock {
    font-variant-numeric: tabular-nums;
  }
</style>
</head>
