<script>
// ─── Filesystem ───
const FS = {
  '/': {
    type: 'folder',
    children: {
      'bin': {
        type: 'folder',
        children: {
          'bash': { type: 'file' },
          'ls': { type: 'file' },
          'cat': { type: 'file' },
          'grep': { type: 'file' },
          'vim': { type: 'file' },
          'python3': { type: 'file' },
          'node': { type: 'file' }
        }
      },
      'etc': {
        type: 'folder',
        children: {
          'hostname': { type: 'file' },
          'passwd': { type: 'file' },
          'fstab': { type: 'file' },
          'nginx': {
            type: 'folder',
            children: {
              'nginx.conf': { type: 'file' },
              'sites-enabled': {
                type: 'folder',
                children: {
                  'default': { type: 'file' }
                }
              }
            }
          },
          'ssh': {
            type: 'folder',
            children: {
              'sshd_config': { type: 'file' },
              'ssh_config': { type: 'file' }
            }
          }
        }
      },
      'home': {
        type: 'folder',
        children: {
          'user': {
            type: 'folder',
            children: {
              'Documents': {
                type: 'folder',
                children: {
                  'resume.txt': { type: 'file' },
                  'notes.md': { type: 'file' },
                  'project-plan.txt': { type: 'file' }
                }
              },
              'Downloads': {
                type: 'folder',
                children: {
                  'archive.tar.gz': { type: 'file' },
                  'image.png': { type: 'file' },
                  'setup.sh': { type: 'file' }
                }
              },
              'Pictures': {
                type: 'folder',
                children: {
                  'wallpaper.jpg': { type: 'file' },
                  'screenshot.png': { type: 'file' },
                  'vacation': {
                    type: 'folder',
                    children: {
                      'beach.jpg': { type: 'file' },
                      'mountain.jpg': { type: 'file' }
                    }
                  }
                }
              },
              'Music': {
                type: 'folder',
                children: {
                  'playlist.m3u': { type: 'file' }
                }
              },
              '.bashrc': { type: 'file' },
              '.profile': { type: 'file' }
            }
          }
        }
      },
      'usr': {
        type: 'folder',
        children: {
          'bin': {
            type: 'folder',
            children: {
              'python3': { type: 'file' },
              'pip3': { type: 'file' }
            }
          },
          'lib': {
            type: 'folder',
            children: {
              'python3': { type: 'folder', children: {} }
            }
          },
          'share': {
            type: 'folder',
            children: {
              'applications': { type: 'folder', children: {} }
            }
          }
        }
      },
      'var': {
        type: 'folder',
        children: {
          'log': {
            type: 'folder',
            children: {
              'syslog': { type: 'file' },
              'auth.log': { type: 'file' },
              'kern.log': { type: 'file' }
            }
          },
          'www': {
            type: 'folder',
            children: {
              'html': {
                type: 'folder',
                children: {
                  'index.html': { type: 'file' }
                }
              }
            }
          },
          'tmp': { type: 'folder', children: {} }
        }
      }
    }
  }
};

let currentPath = '/';

function getNode(path) {
  if (path === '/') return FS['/'];
  const parts = path.split('/').filter(Boolean);
  let node = FS['/'];
  for (const part of parts) {
    if (node.children && node.children[part]) {
      node = node.children[part];
    } else {
      return null;
    }
  }
  return node;
}

function renderFiles() {
  const node = getNode(currentPath);
  const content = document.getElementById('files-content');
  const pathEl = document.getElementById('files-path');
  const upBtn = document.getElementById('files-up');

  pathEl.textContent = currentPath;
  upBtn.disabled = currentPath === '/';

  if (!node || !node.children) {
    content.innerHTML = '<div style="padding:20px;color:var(--text-dim);text-align:center;">Empty directory</div>';
    return;
  }

  const entries = Object.entries(node.children);
  // Sort: folders first, then files, alphabetically within each group
  entries.sort((a, b) => {
    const aIsFolder = a[1].type === 'folder' ? 0 : 1;
    const bIsFolder = b[1].type === 'folder' ? 0 : 1;
    if (aIsFolder !== bIsFolder) return aIsFolder - bIsFolder;
    return a[0].localeCompare(b[0]);
  });

  content.innerHTML = entries.map(([name, entry]) => {
    const isFolder = entry.type === 'folder';
    const iconSvg = isFolder
      ? `<svg viewBox="0 0 24 24" width="20" height="20" fill="currentColor" stroke="none">
           <path d="M10 4H4a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2V8a2 2 0 0 0-2-2h-8l-2-2z"/>
         </svg>`
      : `<svg viewBox="0 0 24 24" width="20" height="20" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
           <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
           <polyline points="14 2 14 8 20 8"/>
         </svg>`;

    return `<div class="fs-item ${isFolder ? 'folder' : 'file'}" 
                 ondblclick="${isFolder ? `navigateTo('${name}')` : ''}"
                 title="${name}">
              <span class="icon">${iconSvg}</span>
              <span class="name">${name}</span>
            </div>`;
  }).join('');
}

function navigateTo(folderName) {
  if (currentPath === '/') {
    currentPath = '/' + folderName;
  } else {
    currentPath = currentPath + '/' + folderName;
  }
  renderFiles();
}

function navigateUp() {
  if (currentPath === '/') return;
  const parts = currentPath.split('/').filter(Boolean);
  parts.pop();
  currentPath = parts.length === 0 ? '/' : '/' + parts.join('/');
  renderFiles();
}

// ─── Notepad ───
let tabs = [];
let activeTabId = null;

function loadTabs() {
  try {
    const saved = localStorage.getItem('notepad-tabs');
    if (saved) {
      const data = JSON.parse(saved);
      tabs = data.tabs || [];
      activeTabId = data.activeTabId || null;
    }
  } catch(e) {
    tabs = [];
    activeTabId = null;
  }
  if (tabs.length === 0) {
    createTab();
  }
  if (!activeTabId || !tabs.find(t => t.id === activeTabId)) {
    activeTabId = tabs[0].id;
  }
}

function saveTabs() {
  localStorage.setItem('notepad-tabs', JSON.stringify({
    tabs: tabs,
    activeTabId: activeTabId
  }));
}

function createTab() {
  const id = 'tab-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5);
  tabs.push({ id, title: 'Untitled', content: '' });
  activeTabId = id;
  saveTabs();
  renderTabs();
  updateEditor();
}

function switchTab(id) {
  // Save current editor content
  const currentTab = tabs.find(t => t.id === activeTabId);
  if (currentTab) {
    currentTab.content = document.getElementById('editor').value;
  }
  activeTabId = id;
  saveTabs();
  renderTabs();
  updateEditor();
}

function closeTab(id, e) {
  if (e) e.stopPropagation();
  const idx = tabs.findIndex(t => t.id === id);
  if (idx === -1) return;
  tabs.splice(idx, 1);
  if (tabs.length === 0) {
    createTab();
    return;
  }
  if (activeTabId === id) {
    activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
  }
  saveTabs();
  renderTabs();
  updateEditor();
}

function renderTabs() {
  const tabsEl = document.getElementById('tabs');
  tabsEl.innerHTML = tabs.map(tab => {
    const isActive = tab.id === activeTabId;
    return `<div class="tab ${isActive ? 'active' : ''}" onclick="switchTab('${tab.id}')">
              <span>${tab.title}</span>
              <button class="tab-close" onclick="closeTab('${tab.id}', event)">×</button>
            </div>`;
  }).join('') + `<button id="new-tab" onclick="createTab()">+</button>`;
}

function updateEditor() {
  const tab = tabs.find(t => t.id === activeTabId);
  const editor = document.getElementById('editor');
  if (tab && editor.value !== tab.content) {
    editor.value = tab.content;
  }
}

// Save content on every input
document.addEventListener('DOMContentLoaded', () => {
  const editor = document.getElementById('editor');
  editor.addEventListener('input', () => {
    const tab = tabs.find(t => t.id === activeTabId);
    if (tab) {
      tab.content = editor.value;
      // Update title based on content
      const lines = editor.value.trim().split('\n');
      tab.title = lines[0] ? lines[0].substring(0, 20) : 'Untitled';
      saveTabs();
      renderTabs();
    }
  });
});

// ─── Window Management ───
function openWindow(app) {
  const winId = app === 'files' ? 'files-window' : 'notepad-window';
  const win = document.getElementById(winId);
  win.style.display = 'flex';
  win.classList.remove('hiding');
  focusWindow(win);
  updateLauncherState();

  if (app === 'files') {
    renderFiles();
  } else if (app === 'notepad') {
    loadTabs();
    renderTabs();
    updateEditor();
  }
}

function closeWindow(app) {
  const winId = app === 'files' ? 'files-window' : 'notepad-window';
  const win = document.getElementById(winId);
  win.classList.add('hiding');
  setTimeout(() => {
    win.style.display = 'none';
    win.classList.remove('hiding');
  }, 150);
  updateLauncherState();
}

function focusWindow(win) {
  document.querySelectorAll('.window').forEach(w => w.classList.remove('focused'));
  win.classList.add('focused');
}

function updateLauncherState() {
  const filesWin = document.getElementById('files-window');
  const notepadWin = document.getElementById('notepad-window');
  document.getElementById('open-files').classList.toggle('active', filesWin.style.display !== 'none' && filesWin.style.display !== '');
  document.getElementById('open-notepad').classList.toggle('active', notepadWin.style.display !== 'none' && notepadWin.style.display !== '');
}

// ─── Draggable Windows ───
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.window-header').forEach(header => {
    let isDragging = false;
    let startX, startY, origX, origY;

    header.addEventListener('mousedown', (e) => {
      if (e.target.closest('.win-close')) return;
      const win = header.closest('.window');
      focusWindow(win);
      isDragging = true;
      startX = e.clientX;
      startY = e.clientY;
      origX = win.offsetLeft;
      origY = win.offsetTop;
      e.preventDefault();
    });

    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      const dx = e.clientX - startX;
      const dy = e.clientY - startY;
      const win = header.closest('.window');
      win.style.left = (origX + dx) + 'px';
      win.style.top = (origY + dy) + 'px';
    });

    document.addEventListener('mouseup', () => {
      isDragging = false;
    });
  });

  // Click on window to focus
  document.querySelectorAll('.window').forEach(win => {
    win.addEventListener('mousedown', () => focusWindow(win));
  });

  // Clock
  function updateClock() {
    const now = new Date();
    const h = now.getHours().toString().padStart(2, '0');
    const m = now.getMinutes().toString().padStart(2, '0');
    document.getElementById('clock').textContent = h + ':' + m;
  }
  updateClock();
  setInterval(updateClock, 30000);

  // Initial render
  renderFiles();
});
